import React, { createContext, useContext, useState, useEffect } from 'react';
import Cookies from 'js-cookie';
import { useDispatch } from 'react-redux';
import { signin } from '../../actions/auth';
import { validateToken } from '../../actions/auth'; // Importera validateToken-funktionen

const AuthContext = createContext();

export const useAuth = () => {
  return useContext(AuthContext);
};

export const AuthProvider = ({ children }) => {
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);
  const [isAuthenticated, setIsAuthenticated] = useState(false); // Uppdatera detta till false initialt
  const dispatch = useDispatch();

  useEffect(() => {
    console.log("cookie: ", Cookies.get('jwtToken'))
    // Kontrollera giltigheten av cookien när komponenten monteras
    const checkAuth = async () => {
      const isValid = await api.validateToken(Cookies.get('jwtToken'));
      setIsAuthenticated(isValid);
      if (!isValid) {
        logout();
      }
    };
    checkAuth();
  }, []);

  const login = async (formData, history) => {
    try {
      setError(null);
      await dispatch(signin(formData, history));
      setIsAuthenticated(true);
      setUser({ username: formData.username });
    } catch (error) {
      setError(error.message);
    }
  };

  const logout = () => {
    Cookies.remove('jwtToken');
    setIsAuthenticated(false);
  };

  const value = {
    user,
    login,
    logout,
    error,
    isAuthenticated,
  };

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
};
